#include <stdio.h>
int sumSubarrayMins(int* arr, int arrSize) {
    int sum = 0;
    int mod = 1000000007;
    for (int i = 0; i < arrSize; i++) {
        int mini = arr[i];
        for (int j = i; j < arrSize; j++) {
            mini = (mini < arr[j]) ? mini : arr[j];
            sum = (sum + mini) % mod;
        }
    }
    return sum;
}
int main() {
    int arr[] = {3, 1, 2, 5};
    int arrSize = sizeof(arr) / sizeof(arr[0]);
    printf("%d\n", sumSubarrayMins(arr, arrSize));
    return 0;
}

